SELECT ranking_category_id, max_ranking
FROM ranking_categories
WHERE ranking_category_type = 'advanced' AND max_ranking > 500;

SELECT COUNT(*) AS total_rewards
FROM rewards
WHERE reward_value > (SELECT AVG(reward_value) FROM rewards);

SELECT reward_name, reward_description, reward_value
FROM rewards
ORDER BY reward_value DESC;

SELECT AVG(rewards.reward_value) AS average_reward_value
FROM reward_redemptions
JOIN rewards ON reward_redemptions.reward_id = rewards.reward_id;

SELECT players.player_id, players.player_name
FROM players
JOIN player_rewards ON players.player_id = player_rewards.player_id;

SELECT DISTINCT p.player_name
FROM players p
INNER JOIN player_rewards pr ON p.player_id = pr.player_id;

SELECT player_id, COUNT(reward_id) AS total_rewards
FROM player_rewards
GROUP BY player_id;

SELECT ranking_category_type, MIN(min_ranking) AS min_ranking, MAX(max_ranking) AS max_ranking
FROM ranking_categories
GROUP BY ranking_category_type;
